extern void messagetrans_file_info(
	char const			*file_name,
	messagetrans_file_flags		*flags,
	int				*size
);

struct messagetrans_control_block {
	int cb [4];
};

typedef struct messagetrans_control_block messagetrans_control_block;

extern void messagetrans_open_file(
	messagetrans_control_block	*cb,
	char const			*file_name,
	char				*buffer
);

osbool msgs_initialise(char *messages_file)
{
	int message_size = 0;

	/* Validate the inputs. */

	if (message_block != NULL || message_buffer != NULL || messages_file == NULL)
		return FALSE;

	/* Read the file details and allocate the necessary memory. */

	if (xmessagetrans_file_info(messages_file, NULL, &message_size) != NULL)
		return FALSE;

	message_block = malloc(sizeof (messagetrans_control_block));
	message_buffer = malloc(message_size);

	if (message_block == NULL || message_buffer == NULL) {
		if (message_block != NULL)
			free(message_block);

		if (message_buffer != NULL)
			free(message_buffer);

		message_block = NULL;
		message_buffer = NULL;

		return FALSE;
	}

	/* Load the file */

	if (xmessagetrans_open_file(message_block, messages_file, message_buffer) != NULL) {
		if (message_block != NULL)
			free(message_block);

		if (message_buffer != NULL)
			free(message_buffer);

		message_block = NULL;
		message_buffer = NULL;

		return FALSE;
	}

	/* Return successfully. */

	return TRUE;
}

void messagetrans_close_file(
	messagetrans_control_block const *cb
);

osbool msgs_terminate(void)
{
	if (message_block == NULL)
		return FALSE;

	messagetrans_close_file(message_block);
	free(message_block);

	if (message_buffer != NULL)
		free(message_buffer);

	message_block = NULL;
	message_buffer = NULL;

	return TRUE;
}

osbool msgs_param_lookup_result(char *token, char *buffer, size_t buffer_size, char *a, char *b, char *c, char *d)
{
	os_error *error;

	if (buffer == NULL || buffer_size == 0)
		return FALSE;

	/* If there's no token, return an empty buffer. */

	if (token == NULL) {
		*buffer = '\0';
		return FALSE;
	}

	/* If there's no message block, instead of using the Global block, return the supplied token. */

	if (message_block == NULL) {
		string_copy(buffer, token, buffer_size);
		return FALSE;
	}

	/* Look up the token. */

	error = xmessagetrans_lookup(message_block, token, buffer, buffer_size, a, b, c, d, NULL, NULL);

	/* If there was an error, return an empty buffer. */

	if (error != NULL) {
		*buffer = '\0';
		return FALSE;
	}

	return TRUE;
}

char *msgs_lookup(char *token, char *buffer, size_t buffer_size)
{
	msgs_param_lookup_result(token, buffer, buffer_size, NULL, NULL, NULL, NULL);

	return buffer;
}

char *msgs_param_lookup(char *token, char *buffer, size_t buffer_size, char *a, char *b, char *c, char *d)
{
	msgs_param_lookup_result(token, buffer, buffer_size, a, b, c, d);

	return buffer;
}

osbool msgs_lookup_result(char *token, char *buffer, size_t buffer_size)
{
	return msgs_param_lookup_result(token, buffer, buffer_size, NULL, NULL, NULL, NULL);
}

static void main_initialise(void)
{
	os_error	*error;
	osspriteop_area	*sprites;

	/* Load the messages file. */

	if (!msgs_initialise("<ExamplApp$Dir>.Messages"))
		error_report_fatal("Failed to load application Messages");

	/* Initialise with the Wimp. */

	wimp_initialise(wimp_VERSION_RO3, main_application_name, NULL, NULL);

	error_initialise(main_application_name, main_application_sprite, NULL);

	event_add_message_handler(message_QUIT, EVENT_MESSAGE_INCOMING, main_message_quit);

	/* Initialise library modules. */

	url_initialise();

	/* Load the application sprites. */

	sprites = resources_load_user_sprite_area("<ExamplApp$Dir>.Sprites");
	if (sprites == NULL)
		error_msgs_report_fatal("BadSprites:Failed to load application Sprites");

	/* Open the templates file. */

	error = xwimp_open_template("<ExamplApp$Dir>.Templates");
	if (error != NULL)
		error_report_program(error);

	/* Initialise the program modules. */

	calc_initialise();
	ibar_initialise(main_application_sprite);
	win_initialise(sprites);

	/* Close the templates file. */

	wimp_close_template();
}

static void main_terminate(void)
{
	wimp_close_down(0);
	msgs_terminate();
}

