#define MENU_MAX_LINE_LEN 64

wimp_menu *menu_create(char *token, int entries)
{
	wimp_menu	*menu = NULL;
	wimp_menu_entry	*entry = NULL;
	char		title[MENU_MAX_LINE_LEN], *buffer = NULL;
	int		len, size;

	/* A menu must have one entry. */

	if (entries < 1)
		return NULL;

	/* Allocate the menu definition block. */

	size = wimp_SIZEOF_MENU(entries);

	menu = malloc(size);
	if (menu == NULL)
		return NULL;

	/* Set up the menu title. */

	msgs_lookup(token, title, MENU_MAX_LINE_LEN);

	len = strlen(title);
	if (len > 12)
		buffer = malloc(len + 1);

	if (buffer != NULL) {
		strncpy(buffer, title, len);
		buffer[len] = '\0';
		menu->title_data.indirected_text.text = buffer;
	} else {
		strncpy(menu->title_data.text, title, 12);
	}

	/* Set up the remainder of the menu header. */

	menu->title_fg = wimp_COLOUR_BLACK;
	menu->title_bg = wimp_COLOUR_LIGHT_GREY;
	menu->work_fg = wimp_COLOUR_BLACK;
	menu->work_bg = wimp_COLOUR_WHITE;
	menu->width = 16;
	menu->height = wimp_MENU_ITEM_HEIGHT;
	menu->gap = wimp_MENU_ITEM_GAP;

	/* Initialise the menu entries. */

	entry = menu->entries;

	while (entries-- > 0) {
		entry->menu_flags = (entries > 0) ? 0 : wimp_MENU_LAST;
		entry->sub_menu = NULL;
		entry->icon_flags = wimp_ICON_TEXT | wimp_ICON_FILLED |
				(wimp_COLOUR_BLACK << wimp_ICON_FG_COLOUR_SHIFT) |
				(wimp_COLOUR_WHITE << wimp_ICON_BG_COLOUR_SHIFT);
		strncpy(entry->data.text, "", 12);

		entry++;
	}

	/* Set the title indirection flag. */

	if (buffer != NULL)
		menu->entries[0].menu_flags |= wimp_MENU_TITLE_INDIRECTED;

	return menu;
}

void menu_entry(wimp_menu *menu, int entry, char *token, wimp_menu *sub_menu)
{
	wimp_menu_entry *definition = NULL;
	char		text[MENU_MAX_LINE_LEN], *buffer = NULL;
	int		len, width;

	if (menu == NULL || text == NULL)
		return;

	/* Update the menu entry definition. */

	definition = menu->entries + entry;

	/* Set up the menu text. */

	msgs_lookup(token, text, MENU_MAX_LINE_LEN);

	len = strlen(text);
	if (len > 12)
		buffer = malloc(len + 1);

	if (buffer != NULL) {
		strncpy(buffer, text, len);
		buffer[len] = '\0';
		definition->data.indirected_text.text = buffer;
		definition->data.indirected_text.validation = "";
		definition->data.indirected_text.size = len + 1;
		definition->icon_flags |= wimp_ICON_INDIRECTED;
	} else {
		strncpy(definition->data.text, text, 12);
	}

	definition->sub_menu = sub_menu;

	/* Recalculate the menu width. */

	width = (16 * strlen(text)) + 16;
	if (width > menu->width)
		menu->width = width;
}

/* Program Info Window. */

window_definition = windows_load_template("ProgInfo");
if (window_definition == NULL) {
	error_msgs_report_error("BadInfoTempl");
	return;
}

prog_info = wimp_create_window(window_definition);
free(window_definition);

event_add_window_icon_click(prog_info, IBAR_PROGINFO_ICON_WEB, ibar_proginfo_web_click);

/* Iconbar Menu. */

ibar_menu = menu_create("IBarMenu", 3);
if (ibar_menu == NULL) {
	error_msgs_report_error("BadIBarMenu");
	return;
}

menu_entry(ibar_menu, IBAR_MENU_INFO, "IBarMenu0", (wimp_menu *) prog_info);
menu_entry(ibar_menu, IBAR_MENU_HELP, "IBarMenu1", NULL);
menu_entry(ibar_menu, IBAR_MENU_QUIT, "IBarMenu2", NULL);

/* Load and create the window. */

window_definition = windows_load_template("Main");
if (window_definition == NULL) {
	error_msgs_report_error("BadMainTempl");
	return;
}

icons = window_definition->icons;

icons[WIN_ICON_SHAPE].data.indirected_sprite.area = sprites;

win_handle = wimp_create_window(window_definition);
free(window_definition);

/* Window Menu. */

win_menu = menu_create("MainMenu", 3);
if (win_menu == NULL) {
	error_msgs_report_error("BadMainMenu");
	return;
}

menu_entry(win_menu, WIN_MENU_DECIMAL1, "MainMenu0", NULL);
menu_entry(win_menu, WIN_MENU_DECIMAL2, "MainMenu1", NULL);
menu_entry(win_menu, WIN_MENU_DECIMAL3, "MainMenu2", NULL);

/* Shapes Menu. */

win_shape_menu = menu_create("ShapeMenu", 3);
if (win_shape_menu == NULL) {
