}

menu_entry(win_shape_menu, WIN_MENU_SHAPE_CIRCLE, "ShapeMenu0", NULL);
menu_entry(win_shape_menu, WIN_MENU_SHAPE_TRIANGLE, "ShapeMenu1", NULL);
menu_entry(win_shape_menu, WIN_MENU_SHAPE_SQUARE, "ShapeMenu2", NULL);

#define CALC_NOT_APPLICABLE_LENGTH 8

static char calc_not_applicable[CALC_NOT_APPLICABLE_LENGTH];

void calc_initialise(void)
{
	calc_set_format(2);
	calc_set_shape(CALC_SHAPE_NONE);
	msgs_lookup("NA", calc_not_applicable, CALC_NOT_APPLICABLE_LENGTH);
}
